9	export async function readMemoryFile(params: {
10	  workspaceDir: string;
11	  extraPaths?: string[];
12	  relPath: string;
13	  from?: number;
14	  lines?: number;
15	}): Promise<{ text: string; path: string }> {
16	  const rawPath = params.relPath.trim();
17	  if (!rawPath) {
18	    throw new Error("path required");
19	  }
20	  const absPath = path.isAbsolute(rawPath)
21	    ? path.resolve(rawPath)
22	    : path.resolve(params.workspaceDir, rawPath);
23	  const relPath = path.relative(params.workspaceDir, absPath).replace(/\\/g, "/");
24	  const inWorkspace = relPath.length > 0 && !relPath.startsWith("..") && !path.isAbsolute(relPath);
25	  const allowedWorkspace = inWorkspace && isMemoryPath(relPath);
26	  let allowedAdditional = false;
27	  if (!allowedWorkspace && (params.extraPaths?.length ?? 0) > 0) {
28	    const additionalPaths = normalizeExtraMemoryPaths(params.workspaceDir, params.extraPaths);
29	    for (const additionalPath of additionalPaths) {
30	      try {
31	        const stat = await fs.lstat(additionalPath);
32	        if (stat.isSymbolicLink()) {
33	          continue;
34	        }
35	        if (stat.isDirectory()) {
36	          if (absPath === additionalPath || absPath.startsWith(`${additionalPath}${path.sep}`)) {
37	            allowedAdditional = true;
38	            break;
39	          }
40	          continue;
41	        }
42	        if (stat.isFile() && absPath === additionalPath && absPath.endsWith(".md")) {
43	          allowedAdditional = true;
44	          break;
45	        }
46	      } catch {}
47	    }
48	  }
49	  if (!allowedWorkspace && !allowedAdditional) {
50	    throw new Error("path required");
51	  }
52	  if (!absPath.endsWith(".md")) {
53	    throw new Error("path required");
54	  }
55	  const statResult = await statRegularFile(absPath);
56	  if (statResult.missing) {
57	    return { text: "", path: relPath };
58	  }
59	  let content: string;
60	  try {
61	    content = await fs.readFile(absPath, "utf-8");
62	  } catch (err) {
63	    if (isFileMissingError(err)) {
64	      return { text: "", path: relPath };
65	    }
66	    throw err;
67	  }
68	  if (!params.from && !params.lines) {
69	    return { text: content, path: relPath };
70	  }
71	  const fileLines = content.split("\n");
72	  const start = Math.max(1, params.from ?? 1);
73	  const count = Math.max(1, params.lines ?? fileLines.length);
74	  const slice = fileLines.slice(start - 1, start - 1 + count);
75	  return { text: slice.join("\n"), path: relPath };
76	}
