48	export async function minimaxUnderstandImage(params: {
49	  apiKey: string;
50	  prompt: string;
51	  imageDataUrl: string;
52	  apiHost?: string;
53	  modelBaseUrl?: string;
54	}): Promise<string> {
55	  const apiKey = normalizeSecretInput(params.apiKey);
56	  if (!apiKey) {
57	    throw new Error("MiniMax VLM: apiKey required");
58	  }
59	  const prompt = params.prompt.trim();
60	  if (!prompt) {
61	    throw new Error("MiniMax VLM: prompt required");
62	  }
63	  const imageDataUrl = params.imageDataUrl.trim();
64	  if (!imageDataUrl) {
65	    throw new Error("MiniMax VLM: imageDataUrl required");
66	  }
67	  if (!/^data:image\/(png|jpeg|webp);base64,/i.test(imageDataUrl)) {
68	    throw new Error("MiniMax VLM: imageDataUrl must be a base64 data:image/(png|jpeg|webp) URL");
69	  }
70	
71	  const host = coerceApiHost({
72	    apiHost: params.apiHost,
73	    modelBaseUrl: params.modelBaseUrl,
74	  });
75	  const url = new URL("/v1/coding_plan/vlm", host).toString();
76	
77	  // Ensure env-based proxy dispatcher is active before the outbound fetch call.
78	  // Without this, HTTP_PROXY/HTTPS_PROXY env vars are silently ignored (#51619).
79	  ensureGlobalUndiciEnvProxyDispatcher();
80	
81	  const res = await fetch(url, {
82	    method: "POST",
83	    headers: {
84	      Authorization: `Bearer ${apiKey}`,
85	      "Content-Type": "application/json",
86	      "MM-API-Source": "OpenClaw",
87	    },
88	    signal: AbortSignal.timeout(60_000),
89	    body: JSON.stringify({
90	      prompt,
91	      image_url: imageDataUrl,
92	    }),
93	  });
94	
95	  const traceId = res.headers.get("Trace-Id") ?? "";
96	  if (!res.ok) {
97	    const body = await res.text().catch(() => "");
98	    const trace = traceId ? ` Trace-Id: ${traceId}` : "";
99	    throw new Error(
100	      `MiniMax VLM request failed (${res.status} ${res.statusText}).${trace}${
101	        body ? ` Body: ${body.slice(0, 400)}` : ""
102	      }`,
103	    );
104	  }
105	
106	  const json = (await res.json().catch(() => null)) as unknown;
107	  if (!isRecord(json)) {
108	    const trace = traceId ? ` Trace-Id: ${traceId}` : "";
109	    throw new Error(`MiniMax VLM response was not JSON.${trace}`);
110	  }
111	
112	  const baseResp = isRecord(json.base_resp) ? (json.base_resp as MinimaxBaseResp) : {};
113	  const code = typeof baseResp.status_code === "number" ? baseResp.status_code : -1;
114	  if (code !== 0) {
115	    const msg = (baseResp.status_msg ?? "").trim();
116	    const trace = traceId ? ` Trace-Id: ${traceId}` : "";
117	    throw new Error(`MiniMax VLM API error (${code})${msg ? `: ${msg}` : ""}.${trace}`);
118	  }
119	
120	  const content = pickString(json, "content").trim();
121	  if (!content) {
122	    const trace = traceId ? ` Trace-Id: ${traceId}` : "";
123	    throw new Error(`MiniMax VLM returned no content.${trace}`);
124	  }
125	
126	  return content;
127	}
