7	
8	export type RedactSensitiveMode = "off" | "tools";
9	type RedactPattern = string | RegExp;
10	
11	const DEFAULT_REDACT_MODE: RedactSensitiveMode = "tools";
12	const DEFAULT_REDACT_MIN_LENGTH = 18;
13	const DEFAULT_REDACT_KEEP_START = 6;
14	const DEFAULT_REDACT_KEEP_END = 4;
15	
16	const DEFAULT_REDACT_PATTERNS: string[] = [
17	  // ENV-style assignments.
18	  String.raw`\b[A-Z0-9_]*(?:KEY|TOKEN|SECRET|PASSWORD|PASSWD)\b\s*[=:]\s*(["']?)([^\s"'\\]+)\1`,
19	  // JSON fields.
20	  String.raw`"(?:apiKey|token|secret|password|passwd|accessToken|refreshToken)"\s*:\s*"([^"]+)"`,
21	  // CLI flags.
22	  String.raw`--(?:api[-_]?key|hook[-_]?token|token|secret|password|passwd)\s+(["']?)([^\s"']+)\1`,
23	  // Authorization headers.
24	  String.raw`Authorization\s*[:=]\s*Bearer\s+([A-Za-z0-9._\-+=]+)`,
25	  String.raw`\bBearer\s+([A-Za-z0-9._\-+=]{18,})\b`,
26	  // PEM blocks.
27	  String.raw`-----BEGIN [A-Z ]*PRIVATE KEY-----[\s\S]+?-----END [A-Z ]*PRIVATE KEY-----`,
28	  // Common token prefixes.
29	  String.raw`\b(sk-[A-Za-z0-9_-]{8,})\b`,
30	  String.raw`\b(ghp_[A-Za-z0-9]{20,})\b`,
31	  String.raw`\b(github_pat_[A-Za-z0-9_]{20,})\b`,
32	  String.raw`\b(xox[baprs]-[A-Za-z0-9-]{10,})\b`,
33	  String.raw`\b(xapp-[A-Za-z0-9-]{10,})\b`,
34	  String.raw`\b(gsk_[A-Za-z0-9_-]{10,})\b`,
35	  String.raw`\b(AIza[0-9A-Za-z\-_]{20,})\b`,
36	  String.raw`\b(pplx-[A-Za-z0-9_-]{10,})\b`,
37	  String.raw`\b(npm_[A-Za-z0-9]{10,})\b`,
38	  // Telegram Bot API URLs embed the token as `/bot<token>/...` (no word-boundary before digits).
39	  String.raw`\bbot(\d{6,}:[A-Za-z0-9_-]{20,})\b`,
40	  String.raw`\b(\d{6,}:[A-Za-z0-9_-]{20,})\b`,
41	];
42	
43	type RedactOptions = {
44	  mode?: RedactSensitiveMode;
45	  patterns?: RedactPattern[];
46	};
47	
48	export type ResolvedRedactOptions = {
49	  mode: RedactSensitiveMode;
50	  patterns: RegExp[];
51	};
52	
53	function normalizeMode(value?: string): RedactSensitiveMode {
54	  return value === "off" ? "off" : DEFAULT_REDACT_MODE;
55	}
56	
57	function parsePattern(raw: RedactPattern): RegExp | null {
58	  if (raw instanceof RegExp) {
59	    if (raw.flags.includes("g")) {
60	      return raw;
61	    }
62	    return new RegExp(raw.source, `${raw.flags}g`);
63	  }
64	  if (!raw.trim()) {
65	    return null;
66	  }
67	  const match = raw.match(/^\/(.+)\/([gimsuy]*)$/);
68	  if (match) {
69	    const flags = match[2].includes("g") ? match[2] : `${match[2]}g`;
70	    return compileConfigRegex(match[1], flags)?.regex ?? null;
71	  }
72	  return compileConfigRegex(raw, "gi")?.regex ?? null;
73	}
74	
75	function resolvePatterns(value?: RedactPattern[]): RegExp[] {
76	  const source = value?.length ? value : DEFAULT_REDACT_PATTERNS;
77	  return source.map(parsePattern).filter((re): re is RegExp => Boolean(re));
78	}
