80	function maskToken(token: string): string {
81	  if (token.length < DEFAULT_REDACT_MIN_LENGTH) {
82	    return "***";
83	  }
84	  const start = token.slice(0, DEFAULT_REDACT_KEEP_START);
85	  const end = token.slice(-DEFAULT_REDACT_KEEP_END);
86	  return `${start}…${end}`;
87	}
88	
89	function redactPemBlock(block: string): string {
90	  const lines = block.split(/\r?\n/).filter(Boolean);
91	  if (lines.length < 2) {
92	    return "***";
93	  }
94	  return `${lines[0]}\n…redacted…\n${lines[lines.length - 1]}`;
95	}
96	
97	function redactMatch(match: string, groups: string[]): string {
98	  if (match.includes("PRIVATE KEY-----")) {
99	    return redactPemBlock(match);
100	  }
101	  const token = groups.findLast((value) => typeof value === "string" && value.length > 0) ?? match;
102	  const masked = maskToken(token);
103	  if (token === match) {
104	    return masked;
105	  }
106	  return match.replace(token, masked);
107	}
