109	function redactText(text: string, patterns: RegExp[]): string {
110	  let next = text;
111	  for (const pattern of patterns) {
112	    next = replacePatternBounded(next, pattern, (...args: string[]) =>
113	      redactMatch(args[0], args.slice(1, args.length - 2)),
114	    );
115	  }
116	  return next;
117	}
